#!/bin/bash
echo "============================================"
echo "  FlipSlab Engine - Full Update v2"
echo "  User Isolation + OpenAI Direct + UI Update"
echo "============================================"
echo ""

PROJECT_DIR=""
if [ -d "/opt/gradeprophet" ]; then
    PROJECT_DIR="/opt/gradeprophet"
elif [ -d "/home/gradeprophet" ]; then
    PROJECT_DIR="/home/gradeprophet"
else
    echo "ERROR: No se encontro el directorio del proyecto"
    exit 1
fi
echo "Directorio: $PROJECT_DIR"

# PASO 1: Leer llaves
echo ""
echo "=== PASO 1: Leyendo llaves ==="
LLAVES_FILE=""
if [ -f "/home/flipcardsuni2/public_html/llaves.txt" ]; then
    LLAVES_FILE="/home/flipcardsuni2/public_html/llaves.txt"
elif [ -f "$PROJECT_DIR/llaves.txt" ]; then
    LLAVES_FILE="$PROJECT_DIR/llaves.txt"
fi

if [ -n "$LLAVES_FILE" ]; then
    echo "Leyendo llaves de: $LLAVES_FILE"
    MONGO_URL=$(grep "^MONGO_URL=" "$LLAVES_FILE" | cut -d'=' -f2-)
    DB_NAME=$(grep "^DB_NAME=" "$LLAVES_FILE" | cut -d'=' -f2-)
    OPENAI_API_KEY=$(grep "^OPENAI_API_KEY=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_CLIENT_ID=$(grep "^EBAY_CLIENT_ID=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_CLIENT_SECRET=$(grep "^EBAY_CLIENT_SECRET=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_DEV_ID=$(grep "^EBAY_DEV_ID=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_RUNAME=$(grep "^EBAY_RUNAME=" "$LLAVES_FILE" | cut -d'=' -f2-)
    REACT_APP_BACKEND_URL=$(grep "^REACT_APP_BACKEND_URL=" "$LLAVES_FILE" | cut -d'=' -f2-)

    cat > "$PROJECT_DIR/backend/.env" << ENVFILE
MONGO_URL=${MONGO_URL:-mongodb://localhost:27017}
DB_NAME=${DB_NAME:-gradeprophet}
OPENAI_API_KEY=${OPENAI_API_KEY}
EBAY_CLIENT_ID=${EBAY_CLIENT_ID}
EBAY_CLIENT_SECRET=${EBAY_CLIENT_SECRET}
EBAY_DEV_ID=${EBAY_DEV_ID}
EBAY_RUNAME=${EBAY_RUNAME}
CORS_ORIGINS=*
ENVFILE
    echo "  backend/.env OK"

    if [ -n "$REACT_APP_BACKEND_URL" ]; then
        cat > "$PROJECT_DIR/frontend/.env" << ENVFILE
REACT_APP_BACKEND_URL=${REACT_APP_BACKEND_URL}
ENVFILE
        echo "  frontend/.env OK"
    fi
else
    echo "AVISO: No se encontro llaves.txt"
fi

# PASO 2: Instalar dependencias
echo ""
echo "=== PASO 2: Dependencias Python ==="
pip3 install openai httpx motor pydantic python-multipart pillow opencv-python-headless "passlib[bcrypt]" "python-jose[cryptography]" 2>&1 | tail -3
echo "  OK"

# PASO 3: Actualizar server.py
echo ""
echo "=== PASO 3: Actualizando server.py ==="
cp "$PROJECT_DIR/backend/server.py" "$PROJECT_DIR/backend/server.py.bak" 2>/dev/null
base64 -d << 'SERVER_EOF' > "$PROJECT_DIR/backend/server.py"

SERVER_EOF
echo "  server.py OK"

# PASO 4: Actualizar LandingPage.jsx
echo ""
echo "=== PASO 4: LandingPage.jsx ==="
cp "$PROJECT_DIR/frontend/src/components/LandingPage.jsx" "$PROJECT_DIR/frontend/src/components/LandingPage.jsx.bak" 2>/dev/null
base64 -d << 'LANDING_EOF' > "$PROJECT_DIR/frontend/src/components/LandingPage.jsx"

LANDING_EOF
echo "  LandingPage.jsx OK"

# PASO 5: Actualizar App.js (withCredentials)
echo ""
echo "=== PASO 5: App.js ==="
cp "$PROJECT_DIR/frontend/src/App.js" "$PROJECT_DIR/frontend/src/App.js.bak" 2>/dev/null
base64 -d << 'APPJS_EOF' > "$PROJECT_DIR/frontend/src/App.js"

APPJS_EOF
echo "  App.js OK"

# PASO 6: Rebuild frontend
echo ""
echo "=== PASO 6: Rebuild frontend ==="
cd "$PROJECT_DIR/frontend"
npm run build 2>&1 | tail -5
echo "  Frontend OK"

# PASO 7: Reiniciar backend
echo ""
echo "=== PASO 7: Reiniciando backend ==="
if command -v supervisorctl &> /dev/null; then
    supervisorctl restart backend 2>/dev/null && echo "  Via supervisor"
elif [ -f "$PROJECT_DIR/restartback.sh" ]; then
    bash "$PROJECT_DIR/restartback.sh" && echo "  Via restartback.sh"
else
    pkill -f "uvicorn.*server:app" 2>/dev/null
    cd "$PROJECT_DIR/backend"
    nohup python3 -m uvicorn server:app --host 0.0.0.0 --port 8001 > "$PROJECT_DIR/backend/backend.log" 2>&1 &
    echo "  Backend reiniciado"
fi

echo ""
echo "============================================"
echo "  UPDATE v2 COMPLETO!"
echo "============================================"
echo ""
echo "Cambios:"
echo "  1. Llaves instaladas (.env)"
echo "  2. AI migrado a OpenAI directo"
echo "  3. CUENTAS INDEPENDIENTES - cada usuario ve solo sus datos"
echo "  4. Landing Page con imagenes nuevas"
echo "  5. Cookies configuradas para auth"
echo ""
echo "Verificar: curl http://localhost:8001/api/"
